const RenderSelectedFieldsForStatic = memo(props => {
	const { component, components, companyData, allComponents, companyUsersArray, setSelectedComponent, selectedComponent, hasAction, user } = props;
	const [loading, setLoading] = useState(false);
	const [timer, setTimer] = useState(0);
	const [showRatings, setShowRatings] = useState(false);
	const getComponentsForListing = options => {
		return components
			.filter(component => component.id === options.component_id)
			.map(cmp => {
				let object = {};
				options.list.map(column => {
					object = { ...object, [column]: cmp.selected_fields.find(field => field.field_name === column).value };
				});
				return object;
			});
	};

	const allSelectedFields =
		component?.selected_fields?.length > 0 &&
		component?.selected_fields
			?.filter(sf => sf.value !== true || sf?.value !== undefined)
			.map((field, index) => {
				if (field?.options?.list?.length > 0 && field?.options?.component_id?.length > 0 && (field?.data_type_name === 'Step List' || field?.data_type_name === 'Component List')) {
					return (
						<div key={index} style={{ width: '100%' }}>
							<ModuleLists modern={true} columns={field.options.list} list={getComponentsForListing(field.options)} />
						</div>
					);
				} else if (field.data_type === 'output' && field.data_type_name !== 'Formula' && field.data_type_name !== 'Record' && field.data_type_name !== 'Filters') {
					return null;
				} else if (field.data_type_name === 'Info') {
					return null;
				} else if (field.data_type_name === 'URL') {
					return null;
				} else if (field.data_type_name === 'Map') {
					return null;
				} else if (field.data_type_name === 'Lookup') {
					return null;
				} else if (field.data_type_name === 'Rewards') {
					return null;
				} else if (field.data_type_name === 'Summary') {
					return null;
				} else if (field.data_type_name === 'Ratings') {
					return null;
				} else if (field.data_type_name === 'ID') {
					const value = R?.find(R?.propEq('field_name', field.field_name))(component.values) ?? null;

					return (
						<div key={index}>
							<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
								<div>{field.field_name}:</div>
								<div>{value === null ? '' : value.value === null ? '' : value?.value?.split(',')[0]}</div>
							</div>
							<hr style={{ borderTop: '0.5px solid #D2D2D2' }} />
						</div>
					);
				} else {
					let cmp = R?.find(R?.propEq('field_name', field?.field_name))(selectedComponent?.component_fields ?? []) ?? {};

					let value = cmp?.value;
					const infoField = component?.selected_fields?.find(sf => sf.data_type_name === 'Info');
					if (infoField) {
						const found = allComponents.find(c => c?.component_fields.filter(cf => cf.component_blueprint_id === infoField.options.component_id && cf.value === value).length > 0);
						if (found) {
							return infoField?.options?.list?.map((label, ix) => {
								const val = found.component_fields.find(cf => cf.field_name === label)?.value ?? '';
								return (
									<div key={ix}>
										<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
											<div>{label}:</div>
											<div>{val}</div>
										</div>
										<hr style={{ borderTop: '0.5px solid #D2D2D2' }} />
									</div>
								);
							});
						}
					}
					if (field.data_type_name === 'Pin' && (field?.value || value)) {
						const location = JSON.parse(field?.value ?? value);
						const status = selectedComponent?.component_fields?.find(f => f.data_type_name === 'Status')?.value;
						if (cmp === undefined) {
							cmp = selectedComponent.component_fields?.find(f => f.data_type_name === 'Pin');
						}

						return (
							<div key={index} style={{ display: '', width: '100%' }}>
								<MapView
									mapkey={companyData.misc_info?.map}
									pins={
										location?.realtime
											? [
												{ ...location.destination, type: 'destination' },
												{ ...location.source, type: 'source' },
												{ ...location.realtime, type: 'realtime' },
											]
											: [
												{ ...location.destination, type: 'destination' },
												{ ...location.source, type: 'source' },
											]
									}
								/>

								<div key={index} className={cls.filtersContainer} style={{ color: 'var(--app-color-gray-dark)', height: 'inherit', width: '100%', display: field?.visible ? '' : 'none' }}>
									<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
										<div style={{ width: '50px', textAlign: 'left' }}>{'From'}:</div>
										<div style={{ width: '80%', textAlign: 'left' }}>{location.source.address}</div>
									</div>
									<hr style={{ borderTop: '0.5px solid #D2D2D2' }} />
									<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
										<div style={{ width: '50px', textAlign: 'left' }}>{'To'}:</div>
										<div style={{ width: '80%', textAlign: 'left' }}>{location.destination.address}</div>
									</div>
								</div>
								<Button
									light
									title={timer != 0 ? 'Stop Location Updates' : field?.options?.realtime ? 'Send Location Updates' : 'Update Location'}
									clicked={() => {
										if (timer === 0) {
											navigator.geolocation.getCurrentPosition(loc => {
												if (location) {
													location.realtime = { lat: loc.coords.latitude, lng: loc.coords.longitude, id: '10' };
													field.value = JSON.stringify(location);

													if (field?.options?.realtime == true) {
														setTimer(
															setInterval(() => {
																setLoading(true);
																updateFieldToComponent({
																	component_id: selectedComponent.id,
																	index: field.index,
																	value: JSON.stringify(location),
																	group: field.group,
																	component_field_id: cmp.id,
																}).subscribe({
																	next: data => {
																		setLoading(false);
																	},
																	error: () => setLoading(false),
																	complete: () => { },
																});
															}, +(cmp?.options?.interval ?? 60000))
														);
													} else {
														setLoading(true);
														updateFieldToComponent({
															component_id: selectedComponent.id,
															index: cmp.index,
															value: JSON.stringify(location),
															group: cmp.group,
															component_field_id: cmp.id,
														}).subscribe({
															next: data => {
																setLoading(false);
															},
															error: () => setLoading(false),
															complete: () => { },
														});
													}
												}
											});
										} else {
											window.clearInterval(timer);
											setTimer(0);
										}
									}}
									loading={loading}
									style={{
										width: '100%',
										display: (selectedComponent?.sttaus === 'Closed' || selectedComponent?.sttaus === 'New' || selectedComponent?.status === companyData?.misc_info?.lock || status === 'Closed' || status === 'New' || status === companyData?.misc_info?.lock) ? 'none' :
											hasAction ? (hasAction.options.action === 'user' && hasAction?.value === user.id) ? '' : 'none' : 'none'
									}}
								/>

								<Button
									light
									title={'Refresh location'}
									clicked={() => {
										setLoading(true);
										getComponentById(selectedComponent.id)
											.pipe(first())
											.subscribe({
												next: data => {
													setSelectedComponent(data);
													setLoading(false);
												},
												error: () => setLoading(false),
											});
									}}
									loading={loading}
									style={{
										width: '100%',
										display: (selectedComponent?.sttaus === 'Closed' || selectedComponent?.sttaus === 'New' || selectedComponent?.status === companyData?.misc_info?.lock || status === 'Closed' || status === 'New' || status === companyData?.misc_info?.lock) ? 'none' :
											hasAction ? (hasAction.options.action === 'user' && hasAction?.value && selectedComponent?.created_by?.id === user.id) ? '' : 'none' : 'none'
									}}
								/>
							</div>
						);
					}
					if (field?.data_type_name === 'Action Button' && field?.options?.action?.length > 0) {

						if (field?.value || value) {
							return (
								<FieldRow width={'100%'} key={index} style={{ flexDirection: 'column', border: '0' }} isProcess visible={field?.value !== undefined ? true : field.visible} mandatory={false} error={field.errors}>
									<div className={cls.centeredDiv} style={{ width: 'inherit', fontSize: '8px' }}>
										{field?.value || value ? (field.options?.notes ? field.options?.notes : field.field_name) : field.options.action === 'user' ? 'Not yet assigned' : 'No status'}
										{field.options.action === 'user' &&
											companyUsersArray?.length > 0 &&
											companyUsersArray
												?.filter(user => user.id === (value ? value : field?.value))
												.map((user, index) => {
													return (
														<div key={index} className={cls.filtersContainer} style={{ fontSize: '12px' }}>
															<UserCard
																ratings={
																	user?.ratings?.length > 0
																		? user?.ratings?.map(rate => {
																			return +rate.ratings;
																		})
																		: []
																}
																simple={true}
																photo={user.photo}
																firstName={user?.first_name}
																lastName={user?.last_name}
																position={user?.positions?.slice(0, 1)?.map(pos => {
																	return pos.name;
																})}
																email={user?.phone ?? user?.email}
																cardClicked={() => setShowRatings(!showRatings)}
																width={'100%'}
															/>

															{showRatings && (
																<div style={{ padding: '10px' }}>
																	<h3>{`User Feedback:`}</h3>
																	{user?.ratings?.length > 0
																		? user?.ratings?.map((rate, i) => {
																			return (
																				<div className={cls.actionsContainer} key={i} style={{ fontSize: '12px', marginBottom: '10px' }}>
																					<div style={{ width: '60%', textAlign: 'left' }}>{`"${rate.comments}"`}</div>

																				</div>
																			);
																		})
																		: null}
																</div>
															)}
														</div>
													);
												})}
									</div>
								</FieldRow>
							);
						} else return null;
					}
					if (field.data_type_name === 'Link') {
						const link = value ? `${value}` : `${field?.value}`;

						return (
							<FieldRow width={isMobile ? '100%' : '50%'} style={{ border: '0' }} key={index} fieldIcon={field.icon} isProcess visible={field?.value !== undefined ? true : field.visible} mandatory={false} error={field.errors} customIconBgColor={'white'}>
								{link?.includes('jpg') || link?.includes('jpeg') || field?.options?.image || link?.includes('png') ? (
									<div className={cls.accordionContainer} onClick={() => window.open(link, '_blank')}>
										<img alt="lg" src={link} style={{ width: '100%', height: '100%', cursor: 'pointer' }} />
									</div>
								) : link?.includes('pdf') ? (
									<div className={cls.accordionContainer} onClick={() => window.open(link, '_blank')}>
										<embed onClick={() => window.open(link, '_blank')} src={`${link}#toolbar=0&navpanes=0&scrollbar=0`} width="400px" height="500px" />
									</div>
								) : (
									<div style={{ width: 'inherit', textDecoration: 'underline', textAlign: 'center', cursor: 'pointer' }} onClick={() => window.open(value, '_blank')}>
										{'Link'}
									</div>
								)}
							</FieldRow>
						);
					}
					if (field.data_type_name === 'Checkbox') {
						return (
							<div key={index}>
								<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
									<div>{field.options.value}:</div>
									<div>{value === undefined ? (field?.value === true ? 'Yes' : 'No') : value == true ? 'Yes' : 'No'}</div>
								</div>
								<hr style={{ borderTop: '0.5px solid #D2D2D2' }} />
							</div>
						);
					}
					if (field.data_type_name === 'Status') {
						return (
							<div key={index}>
								<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
									<div>{'Status'}:</div>
									<div>{selectedComponent?.status ?? value}</div>
								</div>
								<hr style={{ borderTop: '0.5px solid #D2D2D2' }} />
							</div>
						);
					}
					if (field.data_type_name === 'Upload') {
						return (
							<div key={index}>
								<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
									<div>{field.field_name}:</div>
									{(value || field?.value) && (
										<a style={{ fontFamily: 'var(--app-text-main-font)' }} key={index} href={value ? value : field?.value} download="Example-PDF-document" target="_blank" rel="noreferrer">
											{'Download File'}
										</a>
									)}
								</div>
								<hr style={{ borderTop: '0.5px solid #D2D2D2' }} />
							</div>
						);
					}

					if (field?.options?.selection === 'Tiles') {
						const found = allComponents.find(c => c?.component_fields.filter(cf => cf.component_blueprint_id === field.options.component_id && cf.value === value).length > 0);
						if (found) {
							return (
								<div key={index} className={cls.filtersContainer} style={{ color: 'var(--app-color-gray-dark)', height: 'inherit', width: '100%', display: field?.visible ? '' : 'none' }}>
									{field?.options?.names?.map((name, ix) => {
										const val = found.component_fields.find(cf => cf.field_name === name)?.value ?? '';
										if (val?.includes('jpg') || val?.includes('jpeg') || val?.includes('png')) {
											return (
												<div key={ix} style={{ width: 'inherit', display: 'flex', justifyContent: 'right', marginBottom: '20px' }}>
													<img alt="lg" src={val} style={{ objectFit: 'contain', width: '40px', height: '30px', cursor: 'pointer' }} />
												</div>
											);
										}
										return (
											<div key={ix}>
												<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
													<div style={{ width: '20%', textAlign: 'left' }}>{name}:</div>
													<div style={{ width: '80%', textAlign: 'right' }}>{found.component_fields.find(cf => cf.field_name === name)?.value ?? ''}</div>
												</div>
												<hr style={{ borderTop: '0.5px solid #D2D2D2' }} />
											</div>
										);
									})}
								</div>
							);
						}
					}
					return (
						<div key={index} style={{ margin: '10px 0 10px 0', display: field.visible ? '' : 'none' }}>
							<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
								<div>{field.field_name}:</div>
								<div>{value === null || value === undefined ? '' : field.data_type_name === 'Date' ? (moment(new Date(value)).format('DD MMM YYYY') === 'Invalid date' ? '' : moment(new Date(value)).format('DD MMM YYYY')) : value}</div>
							</div>
							<hr style={{ borderTop: '0.5px solid #D2D2D2' }} />
						</div>
					);
				}
			});

	return <div style={{ width: '100%', display: loading ? 'none' : '' }}>{allSelectedFields}</div>;
});

const StaticAccordionCreator = props => {
	const { component } = props;
	const { companyUsersArray } = useSelector(store => store.flowReducer);

	const user = companyUsersArray.find(user => user.id === component.created_by?.id);
	return (
		<div className={cls.centeredDiv} style={{ width: 'inherit', fontSize: '8px', color: 'var(--app-color-gray-lighta)', marginTop: '20px' }}>
			<div style={{ paddingLeft: '5px' }}>{`Created by`}</div>
			<div className={cls.filtersContainer}>
				<UserCard
					title={'Created by:'}
					simple={true}
					photo={user?.photo ?? 'https://s3-symbol-logo.tradingview.com/logo-yazilim--600.png'}
					email={`Transaction Date: ${moment(new Date(component.created_date)).format('DD MMM YYYY')}`}
					firstName={component.created_by?.first_name}
					lastName={component.created_by?.last_name}
					cardClicked={() => { }}
					width={'100%'}
				/>
			</div>
		</div>
	);
};

const StaticAccordionPayments = props => {
	const { component } = props;

	return (
		<div className={cls.filtersContainer} style={{ display: component?.payments ? '' : 'none' }}>
			<div>
				<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
					<div>{'Payments:'}:</div>
					<div>{`${component.payments?.stripe_product}, ID: ${component.payments?.stripe_id.substring(0, 13)}`}</div>
				</div>
				<hr style={{ borderTop: '0.5px solid #D2D2D2' }} />
				<div className={cls.actionsContainer} style={{ fontSize: '12px' }}>
					<div>{'Amount Paid'}:</div>
					<div>{`${component.payments?.stripe_price}`}</div>
				</div>
			</div>
		</div>
	);
};
